{
    RTT_CB *p;
    //
    // Initialize control block
    //
    p = &_RTT;
    p->MaxNumUpBuffers    = RTT_MAX_NUM_UP_BUFFERS;
    p->MaxNumDownBuffers  = RTT_MAX_NUM_DOWN_BUFFERS;
    //
    // Initialize up buffer 0
    //
    p->aUp[0].sName         = "Terminal";
    p->aUp[0].pBuffer       = _acUpBuffer;
    p->aUp[0].SizeOfBuffer  = sizeof(_acUpBuffer);
    p->aUp[0].RdOff         = 0u;
    p->aUp[0].WrOff         = 0u;
    p->aUp[0].Flags         = RTT_MODE_DEFAULT;
    //
    // Initialize down buffer 0
    //
    p->aDown[0].sName         = "Terminal";
    p->aDown[0].pBuffer       = _acDownBuffer;
    p->aDown[0].SizeOfBuffer  = sizeof(_acDownBuffer);
    p->aDown[0].RdOff         = 0u;
    p->aDown[0].WrOff         = 0u;
    p->aDown[0].Flags         = RTT_MODE_DEFAULT;
    //
    // Finish initialization of the control block.
    // Copy Id string in three steps to make sure "SEGGER RTT" is not found
    // in initializer memory (usually flash) by J-Link
    //
    memset((uint8_t*)p->acID, 0x00, sizeof(p->acID));
    strcpy(&p->acID[7], "RTT");
    strcpy(&p->acID[0], "SEGGER");
    p->acID[6] = ' ';
}

{
    unsigned NumBytesToWrite;
    unsigned NumBytesWritten;
    unsigned RdOff;
    unsigned WrOff;
#if RTT_MEMCPY_USE_BYTELOOP
    char    *pDst;
#endif
    //
    // Write data to buffer and handle wrap-around if necessary
    //
    NumBytesWritten = 0u;
    WrOff = pRing->WrOff;
    do
    {
        RdOff = pRing->RdOff;                         // May be changed by host (debug probe) in the meantime
        if (RdOff > WrOff)
        {
            NumBytesToWrite = RdOff - WrOff - 1u;
        }
        else
        {
            NumBytesToWrite = pRing->SizeOfBuffer - (WrOff - RdOff + 1u);
        }
        NumBytesToWrite = MIN(NumBytesToWrite, (pRing->SizeOfBuffer - WrOff));      // Number of bytes that can be written until buffer wrap-around
        NumBytesToWrite = MIN(NumBytesToWrite, NumBytes);
#if RTT_MEMCPY_USE_BYTELOOP
        pDst = pRing->pBuffer + WrOff;
        NumBytesWritten += NumBytesToWrite;
        NumBytes        -= NumBytesToWrite;
        WrOff           += NumBytesToWrite;
        while (NumBytesToWrite--)
        {
            *pDst++ = *pBuffer++;
        };
#else
        RTT_MEMCPY(pRing->pBuffer + WrOff, pBuffer, NumBytesToWrite);
        NumBytesWritten += NumBytesToWrite;
        pBuffer         += NumBytesToWrite;
        NumBytes        -= NumBytesToWrite;
        WrOff           += NumBytesToWrite;
#endif
        if (WrOff == pRing->SizeOfBuffer)
        {
            WrOff = 0u;
        }
        pRing->WrOff = WrOff;
    }
    while (NumBytes);
    //
    return NumBytesWritten;
}

{
    unsigned NumBytesAtOnce;
    unsigned WrOff;
    unsigned Rem;
#if RTT_MEMCPY_USE_BYTELOOP
    char    *pDst;
#endif

    WrOff = pRing->WrOff;
    Rem = pRing->SizeOfBuffer - WrOff;
    if (Rem > NumBytes)
    {
        //
        // All data fits before wrap around
        //
#if RTT_MEMCPY_USE_BYTELOOP
        pDst = pRing->pBuffer + WrOff;
        WrOff += NumBytes;
        while (NumBytes--)
        {
            *pDst++ = *pData++;
        };
        pRing->WrOff = WrOff;
#else
        RTT_MEMCPY(pRing->pBuffer + WrOff, pData, NumBytes);
        pRing->WrOff = WrOff + NumBytes;
#endif
    }
    else
    {
        //
        // We reach the end of the buffer, so need to wrap around
        //
#if RTT_MEMCPY_USE_BYTELOOP
        pDst = pRing->pBuffer + WrOff;
        NumBytesAtOnce = Rem;
        while (NumBytesAtOnce--)
        {
            *pDst++ = *pData++;
        };
        pDst = pRing->pBuffer;
        NumBytesAtOnce = NumBytes - Rem;
        while (NumBytesAtOnce--)
        {
            *pDst++ = *pData++;
        };
        pRing->WrOff = NumBytes - Rem;
#else
        NumBytesAtOnce = Rem;
        RTT_MEMCPY(pRing->pBuffer + WrOff, pData, NumBytesAtOnce);
        NumBytesAtOnce = NumBytes - Rem;
        RTT_MEMCPY(pRing->pBuffer, pData + Rem, NumBytesAtOnce);
        pRing->WrOff = NumBytesAtOnce;
#endif
    }
}

{
    unsigned RdOff;
    unsigned WrOff;
    unsigned r;
    //
    // Avoid warnings regarding volatile access order.  It's not a problem
    // in this case, but dampen compiler enthusiasm.
    //
    RdOff = pRing->RdOff;
    WrOff = pRing->WrOff;
    if (RdOff <= WrOff)
    {
        r = pRing->SizeOfBuffer - 1u - WrOff + RdOff;
    }
    else
    {
        r = RdOff - WrOff - 1u;
    }
    return r;
}

{
    unsigned              Status;
    unsigned              Avail;
    const char           *pData;
    RTT_BUFFER_UP *pRing;

    pData = (const char *)pBuffer;
    //
    // Get "to-host" ring buffer.
    //
    pRing = &_RTT.aUp[BufferIndex];
    //
    // How we output depends upon the mode...
    //
    switch (pRing->Flags)
    {
        case RTT_MODE_NO_BLOCK_SKIP:
            //
            // If we are in skip mode and there is no space for the whole
            // of this output, don't bother.
            //
            Avail = _GetAvailWriteSpace(pRing);
            if (Avail < NumBytes)
            {
                Status = 0u;
            }
            else
            {
                Status = NumBytes;
                _WriteNoCheck(pRing, pData, NumBytes);
            }
            break;
        case RTT_MODE_NO_BLOCK_TRIM:
            //
            // If we are in trim mode, trim to what we can output without blocking.
            //
            Avail = _GetAvailWriteSpace(pRing);
            Status = Avail < NumBytes ? Avail : NumBytes;
            _WriteNoCheck(pRing, pData, Status);
            break;
        case RTT_MODE_BLOCK_IF_FIFO_FULL:
            //
            // If we are in blocking mode, output everything.
            //
            Status = _WriteBlocking(pRing, pData, NumBytes);
            break;
        default:
            Status = 0u;
            break;
    }
    //
    // Finish up.
    //
    return Status;
}

{
    unsigned Status;
    //
    INIT();
    RTT_LOCK();
    //
    // Call the non-locking write function
    //
    Status = RTT_WriteNoLock(BufferIndex, pBuffer, NumBytes);
    //
    // Finish up.
    //
    RTT_UNLOCK();
    //
    return Status;
}

